final:
module top_module(
    input [3:0] bin,
    output [3:0] gray,
    input reset,
    input clk
);reg [3:0] obf_gray_reg;

always @(posedge clk) begin
    if (reset) begin
        obf_gray_reg <= 4'b0000;
    end else begin
        obf_gray_reg <= bin ^ (bin >> 1);
    end
end

assign gray = obf_gray_reg;

endmodule
